import { useState } from "react";

import base from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️", "🫑"];

const toppingPrices = {"🍄": 40, "🧀": 45, "🌽": 30, "🍍": 35, "🧅": 20, "🌶️": 25, "🫑": 30};

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handlePizzaClick(e) {
    const rect = e.currentTarget.getBoundingClientRect();

    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    setPizza((pizza) => [
      ...pizza,
      {
        topping: selected,
        x,
        y,
      },
    ]);
  }

  function calculateTotal() {
    total = 299
	for(topping of pizza) {
		total += toppingPrices[topping.emoji]
	}
	return total
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{calculateTotal()}</h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => setSelected(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        style={{
          position: "relative",
          display: "inline-block",
          margin: 0,
        }}
      >
        <img
          src={base}
          alt="Pizza"
          onClick={handlePizzaClick}
          style={{
            width: 500,
            maxWidth: "100%",
            display: "block",
            cursor: "crosshair",
          }}
        />

        {pizza.map(({ topping, x, y }, index) => (
          <span
            key={index}
            style={{
              position: "absolute",
              left: `${x}%`,
              top: `${y}%`,
              transform: "translate(-50%, -50%)",
              fontSize: "1.5rem",
              lineHeight: 1,
              pointerEvents: "none",
              userSelect: "none",
            }}
          >
            {topping}
          </span>
        ))}
      </figure>
    </main>
  );
}
